return items
  .map(item => {
    const demandDate = new Date(item.json.FKDAT);
    const paymentDate = new Date(item.json.PAY_DATE);

    const diffDays = (paymentDate - demandDate) / (1000 * 60 * 60 * 24);

    if (diffDays >= 0 && diffDays <= 5) {
      return {
        json: {
          customer_id: item.json.KUNNR,
          demand_date: item.json.FKDAT,
          payment_date: item.json.PAY_DATE,
          diff_days: diffDays,
          points: 6000,
          rule: "Paid within 5 days"
        }
      };
    }

    return null;
  })
  .filter(Boolean);

return items.map(item => {
  const agreementValue = Number(item.json.Agreement_Value__c || 0);

  return {
    json: {
      customer_code: item.json.Customer_No__c,
      CreditedById: item.json.CreatedById,
      mobile_number: item.json.MobilePhone,
      amount: agreementValue * 0.0000001, // 0.00001%
      transaction_type: "CREDIT",
      remarks: "Referral Points",
      transaction_note: "Referral reward",
      payment_mode: "cash",
      topup_by: "automation",
      lead_id: item.json.Lead_Id__c,
      created_at: new Date().toISOString()
    }
  };
});

