return items.map(item => {

  const mobile =
    item.json.Account_Mobile_Number__c ||
    item.json.Account_Mobile_1__c ||
    item.json.Mobile_Number__c ||
    null;

  // Referral booking agreement value
  const agreementValue = Number(item.json.Referral_Booking__c_Agreement_Value__c || 0);

  // Calculate 2% points
  const points = Math.round(agreementValue * 0.02);

  return {
    json: {
      customer_code: item.json.ID,
      lead_id: item.json.Lead_Id__c,
      opportunityId: item.json.Opportunity_ID__c,

      // unified mobile (future unique constraint)
      customerMobile: mobile,

      email: item.json.Email_Address__c,
      customerName: item.json.Name,

      amount: points,
      remarks: "Referral Points",
      transaction_note: "Points credited for referral Booking Confirmation",
      payment_mode: "cash",
      topup_by: "automation",

      leadSource: item.json.LeadSource,
      stage: item.json.StageName,

      createdAt: new Date().toISOString()
    }
  };
});

